664	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
665	// session and worktree are optional; machine is derived from os.Hostname().
666	// A stalled in_progress bead (external lease older than HeartbeatTTL) is
667	// reclaimed atomically under the store's lock.
668	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
669		machine, _ := os.Hostname()
670		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
671			machine = envID
672		}
673		return s.WithLock(func() error {
674			beads, _, err := s.readAllLatestRaw()
675			if err != nil {
676				return err
677			}
678			for i := range beads {
679				if beads[i].ID != id {
680					continue
681				}
682				switch beads[i].Status {
683				case StatusOpen:
684					// normal claim path
685				case StatusInProgress:
686					if !claimLeaseIsStale(s, beads[i].Extra, id) {
687						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
688					}
689					// stalled claim — reclaim atomically below
690				default:
691					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
692				}
693				// Refuse claims on beads parked with last_status=push_failed:
694				// the previous attempt landed locally but `git push` was rejected,
695				// so the local commit history exists only on this machine. Re-running
696				// primary work would duplicate or strand commits. The operator must
697				// clear execute-loop-last-status (e.g. by manually pushing or
698				// resetting) before another attempt is allowed.
699				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
700					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
701					if detail != "" {
702						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
703					}
704					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
705				}
706				if err := transitionLifecycleInPlace(&beads[i], StatusInProgress, LifecycleTransitionOptions{
707					Reason: "claim",
708					Actor:  assignee,
709					Source: "Store.ClaimWithOptions",
710				}); err != nil {
711					return err
712				}
713				now := time.Now().UTC()
714				beads[i].Owner = assignee
715				beads[i].UpdatedAt = now
716				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
717				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
718				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
719				if machine != "" {
720					beads[i].Extra["claimed-machine"] = machine
721				}
722				if session != "" {
723					beads[i].Extra["claimed-session"] = session
724				}
725				if worktree != "" {
726					beads[i].Extra["claimed-worktree"] = worktree
727				}
728				if err := s.validateBead(&beads[i]); err != nil {
729					return err
730				}
731				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
732					return err
733				}
734				if err := s.WriteAll(beads); err != nil {
735					return err
736				}
737				return s.TouchClaimHeartbeat(id)
738			}
739			return fmt.Errorf("bead: not found: %s", id)
740		})
741	}
