881	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
882	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
883	// DDx-authored beads always round-trip through `bd import`. Empirically
884	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
885	const MaxFieldBytes = 65535
886	
887	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
888	// need to preserve the full payload should persist it to a sidecar artifact
889	// and store a path reference in the field; this function is the defense-in-
890	// depth cap for code paths that don't. Returns the input unchanged when it
891	// fits; otherwise returns head+tail truncation with a byte-count marker.
892	func capFieldBytes(s string) string {
893		if len(s) <= MaxFieldBytes {
894			return s
895		}
896		// Reserve a marker that always fits; keep head heavy (2/3) so
897		// human-readable context is preserved for the common short-rationale case.
898		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
899		budget := MaxFieldBytes - len(marker)
900		if budget <= 0 {
901			return s[:MaxFieldBytes]
902		}
903		head := (budget * 2) / 3
904		tail := budget - head
905		return s[:head] + marker + s[len(s)-tail:]
906	}
