908	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
909	// cancel writes cancel-requested:true; the worker that honors the cancel writes
910	// cancel-honored:true alongside it.
911	const (
912		ExtraCancelRequested = "cancel-requested"
913		ExtraCancelHonored   = "cancel-honored"
914	)
915	
916	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
917	// if cancel-honored is already set the call is a silent no-op (the prior cancel
918	// was already consumed). Returns true when the marker is now set on the bead
919	// (either by this call or a prior one).
920	func (s *Store) RequestCancel(id string) (bool, error) {
921		var set bool
922		err := s.Update(id, func(b *Bead) {
923			if b.Extra == nil {
924				b.Extra = make(map[string]any)
925			}
926			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
927				set = isExtraTrue(b.Extra[ExtraCancelRequested])
928				return
929			}
930			b.Extra[ExtraCancelRequested] = true
931			set = true
932		})
933		return set, err
934	}
