936	// IsCancelRequested reports whether the bead carries an unconsumed cancel
937	// marker (cancel-requested:true and cancel-honored not yet set).
938	func (s *Store) IsCancelRequested(id string) (bool, error) {
939		b, err := s.Get(id)
940		if err != nil {
941			return false, err
942		}
943		if b == nil || b.Extra == nil {
944			return false, nil
945		}
946		if isExtraTrue(b.Extra[ExtraCancelHonored]) {
947			return false, nil
948		}
949		return isExtraTrue(b.Extra[ExtraCancelRequested]), nil
950	}
