973	func (s *Store) AppendEvent(id string, event BeadEvent) error {
974		if event.CreatedAt.IsZero() {
975			event.CreatedAt = time.Now().UTC()
976		}
977		// Defense in depth: cap every event body regardless of caller. The
978		// reviewer write path separately persists the full stream to an artifact
979		// and emits a <=512-byte body; this cap catches anything else.
980		event.Body = capFieldBytes(event.Body)
981		event.Summary = capFieldBytes(event.Summary)
982		// Two storage shapes are possible here: inline Extra["events"] for active
983		// beads, and a sidecar attachment for closed/archived beads (ADR-004
984		// attachment model). When the bead has been externalized we append to the
985		// sidecar and leave the row untouched aside from updated_at.
986		var appendedToAttachment bool
987		if err := s.Update(id, func(b *Bead) {
988			if b.Extra == nil {
989				b.Extra = make(map[string]any)
990			}
991			if hasEventsAttachment(b) {
992				appendedToAttachment = true
993				return
994			}
995			var events []BeadEvent
996			if raw, ok := b.Extra["events"]; ok {
997				events = decodeBeadEvents(raw)
998			}
999			events = append(events, event)
1000			b.Extra["events"] = encodeEventsForExtra(events)
1001		}); err != nil {
1002			return err
1003		}
1004		if !appendedToAttachment {
1005			return nil
1006		}
1007		// Append to the sidecar under the store lock so concurrent readers and
1008		// writers see a consistent events log.
1009		return s.WithLock(func() error {
1010			existing, err := s.readEventsAttachment(id)
1011			if err != nil {
1012				return err
1013			}
1014			existing = append(existing, event)
1015			return s.writeEventsAttachment(id, existing)
1016		})
1017	}
