1019	// Events returns the bead's evidence history in insertion order. Reads are
1020	// transparent across storage shapes: inline Extra["events"] for active beads,
1021	// or the externalized sidecar referenced by Extra[events_attachment] once the
1022	// bead has been closed.
1023	func (s *Store) Events(id string) ([]BeadEvent, error) {
1024		b, err := s.Get(id)
1025		if err != nil {
1026			return nil, err
1027		}
1028		events, err := s.eventsForBead(b)
1029		if err != nil {
1030			return nil, err
1031		}
1032		if len(events) == 0 {
1033			return []BeadEvent{}, nil
1034		}
1035		out := make([]BeadEvent, len(events))
1036		copy(out, events)
1037		return out, nil
