1055	func decodeBeadEvents(raw any) []BeadEvent {
1056		switch v := raw.(type) {
1057		case []BeadEvent:
1058			out := make([]BeadEvent, len(v))
1059			copy(out, v)
1060			return out
1061		case []any:
1062			out := make([]BeadEvent, 0, len(v))
1063			for _, item := range v {
1064				m, ok := item.(map[string]any)
1065				if !ok {
1066					continue
1067				}
1068				out = append(out, beadEventFromMap(m))
1069			}
1070			return out
1071		case []map[string]any:
1072			out := make([]BeadEvent, 0, len(v))
1073			for _, item := range v {
1074				out = append(out, beadEventFromMap(item))
1075			}
1076			return out
1077		default:
1078			return nil
1079		}
1080	}
