1082	func beadEventFromMap(m map[string]any) BeadEvent {
1083		e := BeadEvent{}
1084		if v, ok := m["kind"].(string); ok {
1085			e.Kind = v
1086		}
1087		if v, ok := m["summary"].(string); ok {
1088			e.Summary = v
1089		}
1090		if v, ok := m["body"].(string); ok {
1091			e.Body = v
1092		}
1093		if v, ok := m["actor"].(string); ok {
1094			e.Actor = v
1095		}
1096		if v, ok := m["source"].(string); ok {
1097			e.Source = v
1098		}
1099		if v, ok := m["created_at"].(string); ok {
1100			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
1101				e.CreatedAt = parsed
1102			}
1103		}
1104		return e
1105	}
