1152	// ErrClosureGateRejected indicates a close was refused because the bead does
1153	// not carry the evidence required for an automated closure: a terminal
1154	// verdict event (review APPROVE with non-empty rationale, or an explicit
1155	// review-skipped / manual-close marker) AND an execution-evidence marker
1156	// (closing_commit_sha, session_id, or an execute-bead success event in the
1157	// events history).
1158	//
1159	// Automated execute-loop paths (execute-bead + reviewer) always go through
1160	// CloseWithEvidence. The plain Store.Close remains as the manual
1161	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
1162	// acceptance §1).
1163	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
1164	
1165	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1166	// rejects only the specific shapes that caused the 2026-04-18/20
1167	// review-malfunction incidents:
1168	//
1169	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1170	//     closing_commit_sha. Rejected by the execution-evidence check —
1171	//     closing_commit_sha must be non-empty OR at least one event must exist.
1172	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1173	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1174	//     parse-mis-extract shape the reviewer bug produced.
1175	//
1176	// Beads without a review step (--no-review, no Reviewer configured, already-
1177	// satisfied paths) pass the gate as long as they carry execution evidence.
1178	// This keeps the surface small: the gate catches known-bad shapes, not every
1179	// conceivable edge case. Additional invariants belong in future dedicated
1180	// beads so the rejection reason stays auditable.
1181	func ClosureGate(b *Bead) error {
1182		if b == nil {
1183			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1184		}
1185		hasClosingCommit := false
1186		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1187			hasClosingCommit = true
1188		}
1189		events := decodeBeadEvents(b.Extra["events"])
1190		// Externalized events still count as evidence for the gate. We only need
1191		// to know whether *some* event history exists, not iterate it; the
1192		// gate's APPROVE-with-empty-rationale check below relies on inline events
1193		// (the verdict is recorded before externalization).
1194		hasAttachedEvents := hasEventsAttachment(b)
1195		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1196		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1197			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1198		}
1199		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1200		for _, e := range events {
1201			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1202				if strings.TrimSpace(e.Body) == "" {
1203					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1204				}
1205			}
1206		}
1207		return nil
1208	}
1209	
1210	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1211	// sessionID is the agent session that completed the work.
1212	// commitSHA is the exact closing commit SHA when it is known.
1213	//
1214	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1215	// via this path without a terminal verdict event plus execution evidence.
1216	// Store.Close is the manual-administration escape hatch when the gate is
1217	// inappropriate.
1218	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1219		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1220			return err
1221		}
1222		// Externalize events only when the gate actually transitioned the bead
1223		// to closed; rejected closes leave the bead open and inline.
1224		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1225			if err := s.externalizeEvents(id); err != nil {
1226				return err
1227			}
1228		}
1229		_ = s.RemoveClaimHeartbeat(id)
1230		s.maybeOpportunisticMaintenance()
1231		return nil
1232	}
