1234	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1235		return s.updateBead(id, true, func(b *Bead) error {
1236			if b.Extra == nil {
1237				b.Extra = make(map[string]any)
1238			}
1239			if sessionID != "" {
1240				b.Extra["session_id"] = sessionID
1241			}
1242			if commitSHA != "" {
1243				b.Extra["closing_commit_sha"] = commitSHA
1244			}
1245			// ClosureGate guards the evidence-close path only; reconcile-close skips
1246			// it by design (TD-031 §5).
1247			if err := ClosureGate(b); err != nil {
1248				// Surface via bead notes so a later operator audit can see why the
1249				// close was refused; a single error path would be dropped by the
1250				// Update callback signature (no error return).
1251				appendClosureRejectNote(b, err)
1252				return nil
1253			}
1254			return transitionLifecycleInPlace(b, StatusClosed, LifecycleTransitionOptions{
1255				ManualClose: true,
1256				Reason:      "close with evidence",
1257				Source:      "Store.CloseWithEvidence",
1258			})
1259		})
1260	}
