1262	func appendClosureRejectNote(b *Bead, err error) {
1263		stamp := time.Now().UTC().Format(time.RFC3339)
1264		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1265		if b.Notes == "" {
1266			b.Notes = note
1267			return
1268		}
1269		b.Notes = b.Notes + "\n" + note
1270	}
