1287	// Reopen sets a bead's status back to open, clears claim fields, optionally
1288	// appends notes, and records an immutable reopen event — all in one atomic
1289	// lock acquisition.
1290	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1291		now := time.Now().UTC()
1292		return s.WithLock(func() error {
1293			beads, _, err := s.readAllLatestRaw()
1294			if err != nil {
1295				return err
1296			}
1297			found := false
1298			for i := range beads {
1299				if beads[i].ID != id {
1300					continue
1301				}
1302				b := &beads[i]
1303				if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
1304					ManualReopen: true,
1305				}); err != nil {
1306					return err
1307				}
1308				b.Owner = ""
1309				b.UpdatedAt = now
1310				if b.Extra == nil {
1311					b.Extra = make(map[string]any)
1312				}
1313				// Clear claim fields
1314				for _, k := range ClaimMetadataExtraKeys {
1315					delete(b.Extra, k)
1316				}
1317				delete(b.Extra, ClaimHeartbeatExtraKey)
1318				// Append notes
1319				if appendNotes != "" {
1320					if b.Notes != "" {
1321						b.Notes = b.Notes + "\n\n" + appendNotes
1322					} else {
1323						b.Notes = appendNotes
1324					}
1325				}
1326				// Record reopen event. If events were externalized at close,
1327				// pull them back inline so the active row carries the full
1328				// history again and the attachment ref is dropped.
1329				if hasEventsAttachment(b) {
1330					if err := s.inlineEventsInPlace(b); err != nil {
1331						return err
1332					}
1333					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1334				}
1335				var events []BeadEvent
1336				if raw, ok := b.Extra["events"]; ok {
1337					events = decodeBeadEvents(raw)
1338				}
1339				evt := BeadEvent{
1340					Kind:      "reopen",
1341					CreatedAt: now,
1342				}
1343				if reason != "" {
1344					evt.Summary = reason
1345				}
1346				events = append(events, evt)
1347				encoded := make([]map[string]any, 0, len(events))
1348				for _, e := range events {
1349					encoded = append(encoded, map[string]any{
1350						"kind":       e.Kind,
1351						"summary":    e.Summary,
1352						"body":       e.Body,
1353						"actor":      e.Actor,
1354						"created_at": e.CreatedAt,
1355						"source":     e.Source,
1356					})
1357				}
1358				b.Extra["events"] = encoded
1359				if err := s.validateBead(b); err != nil {
1360					return err
1361				}
1362				if err := s.runHook("validate-bead-update", b); err != nil {
1363					return err
1364				}
1365				found = true
1366				break
1367			}
1368			if !found {
1369				return fmt.Errorf("bead: not found: %s", id)
1370			}
1371			if err := s.WriteAll(beads); err != nil {
1372				return err
1373			}
1374			return s.RemoveClaimHeartbeat(id)
1375		})
1376	}
