1378	// List returns beads matching optional filters.
1379	// where is an optional map of key=value predicates that match against
1380	// known struct fields and Extra (unknown/workflow-specific) fields.
1381	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1382		beads, err := s.ReadAll()
1383		if err != nil {
1384			return nil, err
1385		}
1386		var result []Bead
1387		for _, b := range beads {
1388			if status != "" && b.Status != status {
1389				continue
1390			}
1391			if label != "" && !containsString(b.Labels, label) {
1392				continue
1393			}
1394			if !matchesWhere(b, where) {
1395				continue
1396			}
1397			result = append(result, b)
1398		}
1399		return result, nil
1400	}
