1402	// matchesWhere returns true if the bead satisfies all key=value predicates.
1403	// It checks known struct fields first, then falls back to Extra.
1404	func matchesWhere(b Bead, where map[string]string) bool {
1405		for k, v := range where {
1406			var actual string
1407			switch k {
1408			case "id":
1409				actual = b.ID
1410			case "title":
1411				actual = b.Title
1412			case "status":
1413				actual = b.Status
1414			case "issue_type":
1415				actual = b.IssueType
1416			case "owner":
1417				actual = b.Owner
1418			case "assignee":
1419				actual = b.Owner
1420			case "parent":
1421				actual = b.Parent
1422			case "description":
1423				actual = b.Description
1424			case "acceptance":
1425				actual = b.Acceptance
1426			case "notes":
1427				actual = b.Notes
1428			default:
1429				// Fall back to Extra map for unknown/workflow-specific fields
1430				if b.Extra != nil {
1431					if ev, ok := b.Extra[k]; ok {
1432						actual = fmt.Sprintf("%v", ev)
1433					}
1434				}
1435			}
1436			if actual != v {
1437				return false
1438			}
1439		}
1440		return true
1441	}
