1443	type lifecycleQueueEntry struct {
1444		Bead
1445		Decision             LifecycleQueueDecision
1446		UnclosedDepIDs       []string
1447		RetryAfter           time.Time
1448		LastStatus           string
1449		LastDetail           string
1450		ExecutionSkipReason  string
1451		SupersededBy         string
1452		EpicClosureCandidate bool
1453	}
1454	
1455	func (s *Store) classifyLifecycleQueue(beads []Bead, now time.Time) []lifecycleQueueEntry {
1456		statusMap := make(map[string]string)
1457		childCount := make(map[string]int)
1458		openChildCount := make(map[string]int)
1459		for _, b := range beads {
1460			statusMap[b.ID] = b.Status
1461			if b.Parent != "" {
1462				childCount[b.Parent]++
1463				if b.Status != StatusClosed {
1464					openChildCount[b.Parent]++
1465				}
1466			}
1467		}
1468	
1469		entries := make([]lifecycleQueueEntry, 0, len(beads))
1470		for _, b := range beads {
1471			unclosed := unclosedDependencyIDs(b, statusMap)
1472			retryAfter, retryActive := activeRetryCooldown(b, now)
1473			executionEligible, executionEligibleKnown := lifecycleExecutionEligible(b)
1474			supersededBy := lifecycleSupersededBy(b)
1475			entry := lifecycleQueueEntry{
1476				Bead:                 b,
1477				UnclosedDepIDs:       unclosed,
1478				RetryAfter:           retryAfter,
1479				LastStatus:           extraStringVal(b.Extra, ExtraLastStatus),
1480				LastDetail:           extraStringVal(b.Extra, ExtraLastDetail),
1481				ExecutionSkipReason:  extraStringVal(b.Extra, ExtraExecutionReason),
1482				SupersededBy:         supersededBy,
1483				EpicClosureCandidate: isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]),
1484			}
1485			entry.Decision = EvaluateLifecycleQueue(LifecycleQueueFacts{
1486				Status:                 b.Status,
1487				Dependencies:           lifecycleDependencyStates(b, statusMap),
1488				ClaimFresh:             b.Status == StatusInProgress && !claimLeaseIsStale(s, b.Extra, b.ID),
1489				RetryCooldownActive:    retryActive,
1490				ExecutionEligible:      executionEligible,
1491				ExecutionEligibleKnown: executionEligibleKnown,
1492				SupersededBy:           supersededBy,
1493				EpicContainer:          isOrdinaryEpicContainer(b, childCount[b.ID]),
1494				ExternalBlockerReason:  extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
1495				LegacyLabels:           b.Labels,
1496			})
1497			entries = append(entries, entry)
1498		}
1499		return entries
1500	}
