1502	func lifecycleDependencyStates(b Bead, statusMap map[string]string) []LifecycleDependencyState {
1503		depIDs := b.DepIDs()
1504		if len(depIDs) == 0 {
1505			return nil
1506		}
1507		deps := make([]LifecycleDependencyState, 0, len(depIDs))
1508		for _, depID := range depIDs {
1509			deps = append(deps, LifecycleDependencyState{Status: statusMap[depID]})
1510		}
1511		return deps
1512	}
1513	
1514	func unclosedDependencyIDs(b Bead, statusMap map[string]string) []string {
1515		var unclosed []string
1516		for _, depID := range b.DepIDs() {
1517			if !LifecycleStatusSatisfiesDependency(statusMap[depID]) {
1518				unclosed = append(unclosed, depID)
1519			}
1520		}
1521		return unclosed
1522	}
