1524	func activeRetryCooldown(b Bead, now time.Time) (time.Time, bool) {
1525		retryAfterStr := extraStringVal(b.Extra, ExtraRetryAfter)
1526		if retryAfterStr == "" {
1527			return time.Time{}, false
1528		}
1529		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1530		if err != nil {
1531			return time.Time{}, false
1532		}
1533		return retryAfter, retryAfter.After(now)
1534	}
