1536	func lifecycleExecutionEligible(b Bead) (bool, bool) {
1537		eligible, ok := b.Extra[ExtraExecutionElig]
1538		if !ok {
1539			return true, false
1540		}
1541		val, isBool := eligible.(bool)
1542		if !isBool {
1543			return true, false
1544		}
1545		return val, true
1546	}
