1593		DependencyWaiting         []string
1594		ProposedOperatorAttention []string
1595		RetryCooldown             []string
1596		ExternalBlocked           []string
1597		NotEligible               []string
1598		Superseded                []string
1599		Epics                     []string
1600		EpicClosureCandidates     []string
1601		NextRetryAfter            string
