1606	// HumanReviewBlockerPressure describes an open human-review blocker and the
1607	// number of active downstream beads that transitively depend on it.
1608	type HumanReviewBlockerPressure struct {
1609		ID                     string
1610		Title                  string
1611		Priority               int
1612		DownstreamBlockedCount int
1613	}
1614	
1615	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1616		out := ReadyExecutionBreakdown{}
1617		beads, err := s.ReadAll()
1618		if err != nil {
1619			return out, err
1620		}
1621		now := time.Now().UTC()
1622		var soonestRetry time.Time
1623		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1624			switch entry.Decision.Bucket {
1625			case LifecycleBucketReady:
1626				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
1627			case LifecycleBucketWaitingDependencies:
1628				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
1629			case LifecycleBucketRetryCooldown:
1630				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
1631				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
1632					soonestRetry = entry.RetryAfter
1633				}
1634			case LifecycleBucketEpicContainer:
1635				if entry.EpicClosureCandidate {
1636					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
1637				} else {
1638					out.Epics = append(out.Epics, entry.ID)
1639				}
1640			case LifecycleBucketNotEligible:
1641				out.NotEligible = append(out.NotEligible, entry.ID)
1642			case LifecycleBucketSuperseded:
1643				out.Superseded = append(out.Superseded, entry.ID)
1644			case LifecycleBucketBlockedExternal:
1645				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
1646			case LifecycleBucketProposed:
1647				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
1648			}
1649		}
1650		if !soonestRetry.IsZero() {
1651			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1652		}
1653		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
1654		return out, nil
1655	}
1656	
1657	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
1658		byID := make(map[string]Bead, len(beads))
1659		reverseDeps := make(map[string][]string, len(beads))
1660		for _, b := range beads {
1661			byID[b.ID] = b
1662			if !activeForDependencyPressure(b) {
1663				continue
1664			}
1665			for _, dep := range b.Dependencies {
1666				if dep.DependsOnID == "" {
1667					continue
1668				}
1669				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
1670			}
1671		}
1672	
1673		var blockers []HumanReviewBlockerPressure
1674		totalBlocked := map[string]struct{}{}
1675		for _, b := range beads {
1676			if !isHumanReviewBlocker(b) {
1677				continue
1678			}
1679			seen := map[string]struct{}{}
1680			var walk func(string)
1681			walk = func(id string) {
1682				for _, childID := range reverseDeps[id] {
1683					if childID == b.ID {
1684						continue
1685					}
1686					child, ok := byID[childID]
1687					if !ok || !activeForDependencyPressure(child) {
1688						continue
1689					}
1690					if _, exists := seen[childID]; exists {
1691						continue
1692					}
1693					seen[childID] = struct{}{}
1694					totalBlocked[childID] = struct{}{}
1695					walk(childID)
1696				}
1697			}
1698			walk(b.ID)
1699			if len(seen) == 0 {
1700				// A proposed/needs-human bead with no active downstream is operator
1701				// attention only; it does not contribute to HumanReviewBlockers.
1702				continue
1703			}
1704			blockers = append(blockers, HumanReviewBlockerPressure{
1705				ID:                     b.ID,
1706				Title:                  b.Title,
1707				Priority:               b.Priority,
1708				DownstreamBlockedCount: len(seen),
1709			})
1710		}
1711	
1712		sort.SliceStable(blockers, func(i, j int) bool {
1713			if blockers[i].Priority != blockers[j].Priority {
1714				return blockers[i].Priority < blockers[j].Priority
1715			}
1716			return blockers[i].ID < blockers[j].ID
1717		})
1718		return blockers, len(totalBlocked)
1719	}
1720	
1721	func isHumanReviewBlocker(b Bead) bool {
1722		// Post-lifecycle: proposed status is the canonical operator-attention signal.
1723		if b.Status == StatusProposed {
1724			return true
1725		}
1726		// Legacy: open beads with investigation/human-review labels still count.
1727		if b.Status != StatusOpen {
1728			return false
1729		}
1730		for _, label := range b.Labels {
1731			switch label {
1732			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
1733				return true
1734			}
1735		}
1736		return false
1737	}
1738	
1739	func activeForDependencyPressure(b Bead) bool {
1740		switch b.Status {
1741		case StatusClosed, StatusCancelled:
1742			return false
1743		default:
1744			return true
1745		}
1746	}
