1821	// BlockedAll returns open beads that are currently not runnable, classified
1822	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1823	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1824	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1825	// that is both dep-blocked and cooldown-parked is reported as dependency-
1826	// blocked, because deps are the stronger blocker.
1827	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1828		beads, err := s.ReadAll()
1829		if err != nil {
1830			return nil, err
1831		}
1832	
1833		now := time.Now().UTC()
1834		var entries []BlockedBead
1835		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1836			switch entry.Decision.Bucket {
1837			case LifecycleBucketWaitingDependencies:
1838				entries = append(entries, BlockedBead{
1839					Bead: entry.Bead,
1840					Blocker: Blocker{
1841						Kind:           BlockerKindDependency,
1842						UnclosedDepIDs: entry.UnclosedDepIDs,
1843					},
1844				})
1845			case LifecycleBucketBlockedExternal:
1846				reason := entry.Decision.ExternalBlockerReason
1847				if reason == "" && len(entry.Decision.Issues) > 0 {
1848					reason = entry.Decision.Issues[0].Detail
1849				}
1850				entries = append(entries, BlockedBead{
1851					Bead: entry.Bead,
1852					Blocker: Blocker{
1853						Kind:   BlockerKindBlockedStatus,
1854						Reason: reason,
1855					},
1856				})
1857			case LifecycleBucketProposed:
1858				entries = append(entries, BlockedBead{
1859					Bead: entry.Bead,
1860					Blocker: Blocker{
1861						Kind:   BlockerKindOperatorAttention,
1862						Reason: "status=proposed requires operator attention",
1863					},
1864				})
1865			case LifecycleBucketEpicContainer:
1866				entries = append(entries, BlockedBead{
1867					Bead: entry.Bead,
1868					Blocker: Blocker{
1869						Kind:   BlockerKindEpicOnly,
1870						Reason: "ordinary ddx work skips epic/container beads",
1871					},
1872				})
1873			case LifecycleBucketNotEligible:
1874				entries = append(entries, BlockedBead{
1875					Bead: entry.Bead,
1876					Blocker: Blocker{
1877						Kind:   BlockerKindNotEligible,
1878						Reason: entry.ExecutionSkipReason,
1879					},
1880				})
1881			case LifecycleBucketSuperseded:
1882				entries = append(entries, BlockedBead{
1883					Bead: entry.Bead,
1884					Blocker: Blocker{
1885						Kind:   BlockerKindSuperseded,
1886						Reason: entry.SupersededBy,
1887					},
1888				})
1889			case LifecycleBucketRetryCooldown:
1890				entries = append(entries, BlockedBead{
1891					Bead: entry.Bead,
1892					Blocker: Blocker{
1893						Kind:           BlockerKindRetryCooldown,
1894						NextEligibleAt: entry.RetryAfter.UTC().Format(time.RFC3339),
1895						LastStatus:     entry.LastStatus,
1896						LastDetail:     entry.LastDetail,
1897					},
1898				})
1899			}
1900		}
1901	
1902		sort.SliceStable(entries, func(i, j int) bool {
1903			if entries[i].Priority != entries[j].Priority {
1904				return entries[i].Priority < entries[j].Priority
1905			}
1906			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1907				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1908			}
1909			return entries[i].ID < entries[j].ID
1910		})
1911		return entries, nil
1912	}
