1927	func sortBeadsForQueue(beads []Bead) {
1928		sort.SliceStable(beads, func(i, j int) bool {
1929			if beads[i].Priority != beads[j].Priority {
1930				return beads[i].Priority < beads[j].Priority
1931			}
1932			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1933			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1934			if iok != jok {
1935				return iok
1936			}
1937			if iok && jok && ir != jr {
1938				return ir < jr
1939			}
1940			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1941				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1942			}
1943			return beads[i].ID < beads[j].ID
1944		})
1945	}
