1988	// Status returns aggregate counts.
1989	func (s *Store) Status() (*StatusCounts, error) {
1990		beads, err := s.ReadAll()
1991		if err != nil {
1992			return nil, err
1993		}
1994		ready, err := s.Ready()
1995		if err != nil {
1996			return nil, err
1997		}
1998		workerReady, err := s.ReadyExecution()
1999		if err != nil {
2000			return nil, err
2001		}
2002		needsHuman, err := s.ProposedOperatorAttention()
2003		if err != nil {
2004			return nil, err
2005		}
2006	
2007		// Pull in archive partner so totals survive `bead migrate` — the archive
2008		// only carries closed beads, so Ready/Blocked aren't affected.
2009		seen := make(map[string]bool, len(beads))
2010		all := make([]Bead, 0, len(beads))
2011		for _, b := range beads {
2012			if seen[b.ID] {
2013				continue
2014			}
2015			seen[b.ID] = true
2016			all = append(all, b)
2017		}
2018		if s.Collection == DefaultCollection {
2019			archive := s.archivePartner()
2020			if archived, aerr := archive.ReadAll(); aerr == nil {
2021				for _, b := range archived {
2022					if seen[b.ID] {
2023						continue
2024					}
2025					seen[b.ID] = true
2026					all = append(all, b)
2027				}
2028			}
2029		}
2030	
2031		counts := &StatusCounts{
2032			Total:             len(all),
2033			Ready:             len(ready),
2034			WorkerReady:       len(workerReady),
2035			NeedsHuman:        len(needsHuman),
2036			OperatorAttention: len(needsHuman),
2037		}
2038		for _, b := range all {
2039			switch b.Status {
2040			case StatusOpen:
2041				counts.Open++
2042			case StatusInProgress:
2043				counts.InProgress++
2044			case StatusClosed:
2045				counts.Closed++
2046			case StatusBlocked:
2047				counts.Blocked++
2048			case StatusProposed:
2049				counts.Proposed++
2050			case StatusCancelled:
2051				counts.Cancelled++
2052			}
2053		}
2054		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
2055			switch entry.Decision.Bucket {
2056			case LifecycleBucketWaitingDependencies:
2057				counts.DependencyWaiting++
2058			case LifecycleBucketBlockedExternal:
2059				counts.ExternalBlocked++
2060			}
2061		}
2062		return counts, nil
2063	}
