2065	// DepAdd adds a dependency: id depends on depID.
2066	func (s *Store) DepAdd(id, depID string) error {
2067		return s.WithLock(func() error {
2068			beads, _, err := s.readAllLatestRaw()
2069			if err != nil {
2070				return err
2071			}
2072			var target *Bead
2073			depExists := false
2074			for i := range beads {
2075				if beads[i].ID == id {
2076					target = &beads[i]
2077				}
2078				if beads[i].ID == depID {
2079					depExists = true
2080				}
2081			}
2082			if target == nil {
2083				return fmt.Errorf("bead: not found: %s", id)
2084			}
2085			if !depExists {
2086				return fmt.Errorf("bead: dependency not found: %s", depID)
2087			}
2088			if id == depID {
2089				return fmt.Errorf("bead: cannot depend on self")
2090			}
2091			if target.HasDep(depID) {
2092				return nil // already exists
2093			}
2094	
2095			// Check for circular dependency
2096			depMap := make(map[string][]string)
2097			for _, b := range beads {
2098				depMap[b.ID] = b.DepIDs()
2099			}
2100			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
2101			if hasCycle(depMap, id) {
2102				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
2103			}
2104	
2105			target.AddDep(depID, "blocks")
2106			target.UpdatedAt = time.Now().UTC()
2107			return s.WriteAll(beads)
2108		})
2109	}
