2118	// DepTree returns a text representation of the dependency tree.
2119	func (s *Store) DepTree(rootID string) (string, error) {
2120		beads, err := s.ReadAll()
2121		if err != nil {
2122			return "", err
2123		}
2124		// Pull in archive partner so the tree survives `bead migrate` — closed
2125		// beads stored only in the archive must still appear.
2126		if s.Collection == DefaultCollection {
2127			archive := s.archivePartner()
2128			if archived, aerr := archive.ReadAll(); aerr == nil {
2129				seen := make(map[string]bool, len(beads))
2130				for _, b := range beads {
2131					seen[b.ID] = true
2132				}
2133				for _, b := range archived {
2134					if seen[b.ID] {
2135						continue
2136					}
2137					beads = append(beads, b)
2138				}
2139			}
2140		}
2141		byID := make(map[string]*Bead)
2142		for i := range beads {
2143			byID[beads[i].ID] = &beads[i]
2144		}
2145	
2146		if rootID != "" {
2147			target, ok := byID[rootID]
2148			if !ok {
2149				return "", fmt.Errorf("bead: not found: %s", rootID)
2150			}
2151			var sb strings.Builder
2152			// Walk up: show the dependency chain (what this node depends on)
2153			depChain := s.depChainUp(byID, rootID)
2154			if len(depChain) > 0 {
2155				// Print deps as the tree root(s), with the target as their child
2156				for _, depID := range depChain {
2157					if dep, ok := byID[depID]; ok {
2158						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
2159					}
2160				}
2161			}
2162			// Print the target node
2163			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
2164			// Print dependents (what depends on this node)
2165			var children []string
2166			for _, other := range sortedKeys(byID) {
2167				if byID[other].HasDep(rootID) {
2168					children = append(children, other)
2169				}
2170			}
2171			for _, child := range children {
2172				s.printTree(&sb, byID, child, "  ", true)
2173			}
2174			return sb.String(), nil
2175		}
2176	
2177		// Find roots (beads that have no dependencies themselves)
2178		var roots []string
2179		for _, b := range beads {
2180			if len(b.Dependencies) == 0 {
2181				roots = append(roots, b.ID)
2182			}
2183		}
2184		sort.Strings(roots)
2185	
2186		var sb strings.Builder
2187		for i, root := range roots {
2188			s.printTree(&sb, byID, root, "", i == len(roots)-1)
2189		}
2190		return sb.String(), nil
2191	}
2192	
2193	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
2194		b, ok := byID[id]
2195		if !ok {
2196			return
2197		}
2198	
2199		connector := "├── "
2200		if last {
2201			connector = "└── "
2202		}
2203		if prefix == "" {
2204			connector = ""
2205		}
2206	
2207		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
2208	
2209		// Find beads that depend on this one (children in the tree)
2210		var children []string
2211		for _, other := range sortedKeys(byID) {
2212			if byID[other].HasDep(id) {
2213				children = append(children, other)
2214			}
2215		}
2216	
2217		childPrefix := prefix
2218		if prefix != "" {
2219			if last {
2220				childPrefix += "    "
2221			} else {
2222				childPrefix += "│   "
2223			}
2224		}
2225	
2226		for i, child := range children {
2227			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
2228		}
2229	}
