2240	// validateBead checks core invariants that must hold for any bead (create or update).
2241	func (s *Store) validateBead(b *Bead) error {
2242		if strings.TrimSpace(b.Title) == "" {
2243			return fmt.Errorf("bead: title is required")
2244		}
2245		if b.Priority < MinPriority || b.Priority > MaxPriority {
2246			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
2247		}
2248		if !IsCanonicalStatus(b.Status) {
2249			return fmt.Errorf("bead: invalid status: %s", b.Status)
2250		}
2251		// Self-ref check
2252		for _, depID := range b.DepIDs() {
2253			if depID == b.ID && b.ID != "" {
2254				return fmt.Errorf("bead: cannot depend on self")
2255			}
2256		}
2257		return nil
2258	}
