2260	// detectPrefix derives the bead ID prefix from the repository/directory name,
2261	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
2262	// workingDir is the project root to use for git commands; when empty the
2263	// process working directory is used (legacy behaviour, prone to worktree
2264	// path contamination). Falls back to DefaultPrefix if detection fails.
2265	func detectPrefix(workingDir string) string {
2266		// Try git repo root name first, running from the known project root so
2267		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
2268		// contaminate the prefix with their ephemeral directory names.
2269		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
2270		if out, err := cmd.Output(); err == nil {
2271			root := strings.TrimSpace(string(out))
2272			if root != "" {
2273				return filepath.Base(root)
2274			}
2275		}
2276		// Fall back to the provided working dir, then cwd.
2277		if workingDir != "" {
2278			return filepath.Base(workingDir)
2279		}
2280		if wd, err := os.Getwd(); err == nil {
2281			return filepath.Base(wd)
2282		}
2283		return DefaultPrefix
2284	}
