2286	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
2287		v := os.Getenv(envKey)
2288		if v == "" {
2289			return fallback
2290		}
2291		// Try as seconds (plain number)
2292		if secs, err := strconv.ParseFloat(v, 64); err == nil {
2293			return time.Duration(secs * float64(time.Second))
2294		}
2295		// Try as Go duration
2296		if d, err := time.ParseDuration(v); err == nil {
2297			return d
2298		}
2299		return fallback
2300	}
