2327	// hasCycle detects cycles in the dependency graph starting from startID.
2328	func hasCycle(deps map[string][]string, startID string) bool {
2329		visited := make(map[string]bool)
2330		stack := make(map[string]bool)
2331	
2332		var visit func(string) bool
2333		visit = func(id string) bool {
2334			visited[id] = true
2335			stack[id] = true
2336	
2337			for _, dep := range deps[id] {
2338				if !visited[dep] {
2339					if visit(dep) {
2340						return true
2341					}
2342				} else if stack[dep] {
2343					return true
2344				}
2345			}
2346	
2347			stack[id] = false
2348			return false
2349		}
2350	
2351		return visit(startID)
2352	}
