181	func (f *CommandFactory) newWorkFocusCommand() *cobra.Command {
182		cmd := &cobra.Command{
183			Use:   "focus",
184			Short: "Show work requiring operator attention",
185			Long: `focus shows a read-only summary of queue items that require operator
186	attention — proposed beads, external blockers, dependency-waiting or
187	planning-required beads — along with a conservative worker-capacity
188	recommendation based on observable queue depth and in-progress signals.
189	
190	Unlike 'ddx work plan', focus is designed for interactive queue stewardship:
191	it surfaces the items workers will NOT pick up and recommends operator actions.
192	Worker-ready beads are not listed as primary intervention items; they appear
193	only as a depth summary.
194	
195	Use --json for machine-readable output with stable keys:
196	  human_required, blocked_or_planning, ready_summary,
197	  worker_recommendation, unknowns
198	`,
199			Example: `  # Show intervention queue in human-readable format
200	  ddx work focus
201	
202	  # Machine-readable output
203	  ddx work focus --json | jq '.human_required'`,
204			Args: cobra.NoArgs,
205			RunE: f.runWorkFocus,
206		}
207		cmd.Flags().Bool("json", false, "Output as JSON object with stable keys")
208		return cmd
209	}
210	
211	func (f *CommandFactory) runWorkFocus(cmd *cobra.Command, _ []string) error {
212		asJSON, _ := cmd.Flags().GetBool("json")
213	
214		ddxDir := f.WorkingDir + "/.ddx"
215		store := bead.NewStore(ddxDir)
216	
217		report, err := buildWorkFocusReport(store)
218		if err != nil {
219			return err
220		}
221	
222		if asJSON {
223			enc := json.NewEncoder(cmd.OutOrStdout())
224			enc.SetIndent("", "  ")
225			return enc.Encode(report)
226		}
227		return printWorkFocusText(cmd, report)
228	}
229	
230	func printWorkFocusText(cmd *cobra.Command, r WorkFocusReport) error {
231		out := cmd.OutOrStdout()
232	
233		// Section: Operator attention
234		fmt.Fprintf(out, "=== Operator attention (%d) ===\n", len(r.HumanRequired))
235		if len(r.HumanRequired) == 0 {
236			fmt.Fprintln(out, "  (none)")
237		} else {
238			for _, item := range r.HumanRequired {
239				fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
240				if item.Reason != "" {
241					fmt.Fprintf(out, "       reason: %s\n", item.Reason)
242				}
243				if item.SuggestedAction != "" {
244					fmt.Fprintf(out, "       suggested action: %s\n", item.SuggestedAction)
245				}
246			}
247		}
248	
249		// Section: Blocked / planning
250		fmt.Fprintf(out, "\n=== Blocked / planning (%d) ===\n", len(r.BlockedOrPlanning))
251		if len(r.BlockedOrPlanning) == 0 {
252			fmt.Fprintln(out, "  (none)")
253		} else {
254			for _, item := range r.BlockedOrPlanning {
255				fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
256				if item.Detail != "" {
257					fmt.Fprintf(out, "       blocker: %s — %s\n", item.BlockerKind, item.Detail)
258				} else {
259					fmt.Fprintf(out, "       blocker: %s\n", item.BlockerKind)
260				}
261			}
262		}
263	
264		// Section: Worker-ready summary
265		fmt.Fprintf(out, "\n=== Worker-ready summary ===\n")
266		fmt.Fprintf(out, "  %d bead(s) ready for worker execution (%s)\n", r.ReadySummary.Count, r.ReadySummary.Depth)
267	
268		// Section: Worker recommendation
269		fmt.Fprintf(out, "\n=== Worker recommendation ===\n")
270		fmt.Fprintf(out, "  %s\n", r.WorkerRecommendation)
271	
272		// Section: Unknowns
273		fmt.Fprintf(out, "\n=== Unknowns ===\n")
274		if len(r.Unknowns) == 0 {
275			fmt.Fprintln(out, "  (none)")
276		} else {
277			for _, u := range r.Unknowns {
278				fmt.Fprintf(out, "  - %s\n", u)
279			}
280		}
281	
282		return nil
283	}
